import React from 'react';
import { STATUS_OPTIONS, getStatusBadge, getStatusIcon } from '../../utils/statusHelpers';

export default function ParcelsTable({ parcels, onStatusChange, isUpdating }) {
  return (
    <div className="card shadow-sm border-0">
      <div className="card-body p-4">
        <div className="d-flex justify-content-between align-items-center mb-3">
          <h2 className="h4 mb-0">All Parcels</h2>
          <span className="badge bg-secondary">{parcels.length} records</span>
        </div>
        <div className="table-responsive">
          <table className="table table-hover align-middle">
            <thead className="table-light">
              <tr>
                <th>Tracking ID</th>
                <th>Sender</th>
                <th>Receiver</th>
                <th>Route</th>
                <th>Weight (kg)</th>
                <th>Cost (₹)</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {parcels.map((parcel) => (
                <ParcelRow
                  key={parcel.id}
                  parcel={parcel}
                  onStatusChange={onStatusChange}
                  isUpdating={isUpdating}
                />
              ))}
            </tbody>
          </table>
          {!parcels.length && <p className="text-center text-muted py-4">No parcels registered yet.</p>}
        </div>
      </div>
    </div>
  );
}

function ParcelRow({ parcel, onStatusChange, isUpdating }) {
  const StatusIcon = getStatusIcon(parcel.status);

  return (
    <tr>
      <td className="fw-semibold text-primary">{parcel.trackingId}</td>
      <td>{parcel.senderName}</td>
      <td>{parcel.receiverName}</td>
      <td>
        {parcel.sourceCity} → {parcel.destinationCity}
      </td>
      <td>{parcel.weightKg}</td>
      <td>{parcel.costInr}</td>
      <td>
        <div className="d-flex align-items-center gap-2">
          <span className={`badge bg-${getStatusBadge(parcel.status)} d-flex align-items-center gap-1`}>
            <StatusIcon size={14} />
            {parcel.status}
          </span>
          <select
            className="form-select form-select-sm"
            value={parcel.status}
            disabled={isUpdating}
            onChange={(e) => onStatusChange(parcel.id, e.target.value)}
          >
            {STATUS_OPTIONS.map((status) => (
              <option key={status} value={status}>
                {status}
              </option>
            ))}
          </select>
        </div>
      </td>
    </tr>
  );
}
